 27	type WatcherHub struct {
 28		mu       sync.Mutex
 29		watchers map[string]*projectWatcher
 30		interval time.Duration
 31		ctx      context.Context
 32		cancel   context.CancelFunc
 33	}
 34	
 35	// NewWatcherHub creates a hub that polls each watched project at interval.
 36	func NewWatcherHub(interval time.Duration) *WatcherHub {
 37		ctx, cancel := context.WithCancel(context.Background())
 38		return &WatcherHub{
 39			watchers: make(map[string]*projectWatcher),
 40			interval: interval,
 41			ctx:      ctx,
 42			cancel:   cancel,
 43		}
 44	}
 45	
