 52	// projectID (the project root directory). A new per-project watcher is
 53	// started on first Subscribe call. The returned func unsubscribes.
 54	func (h *WatcherHub) SubscribeLifecycle(projectID string) (<-chan LifecycleEvent, func()) {
 55		h.mu.Lock()
 56		pw, ok := h.watchers[projectID]
 57		if !ok {
 58			store := NewStore(projectID + "/.ddx")
 59			pw = newProjectWatcher(store, h.interval)
 60			h.watchers[projectID] = pw
 61			go pw.run(h.ctx)
 62		}
 63		h.mu.Unlock()
 64		return pw.subscribe()
 65	}
