 72	}
 73	
 74	// projectWatcher polls a single bead store and broadcasts lifecycle events.
 75	type projectWatcher struct {
 76		store    *Store
 77		interval time.Duration
 78	
 79		mu       sync.Mutex
 80		subs     []chan LifecycleEvent
 81		snapshot map[string]beadState
 82		lastMod  time.Time
 83	}
