 85	func newProjectWatcher(store *Store, interval time.Duration) *projectWatcher {
 86		return &projectWatcher{
 87			store:    store,
 88			interval: interval,
 89			snapshot: make(map[string]beadState),
 90		}
 91	}
 92	
 93	func (pw *projectWatcher) subscribe() (<-chan LifecycleEvent, func()) {
 94		ch := make(chan LifecycleEvent, 16)
 95		pw.mu.Lock()
 96		pw.subs = append(pw.subs, ch)
 97		pw.mu.Unlock()
 98		unsub := func() {
 99			pw.mu.Lock()
100			defer pw.mu.Unlock()
101			for i, sub := range pw.subs {
102				if sub == ch {
103					pw.subs = append(pw.subs[:i], pw.subs[i+1:]...)
104					close(ch)
105					return
106				}
107			}
108		}
109		return ch, unsub
110	}
