168					Kind:      "status_changed",
169					Summary:   fmt.Sprintf("status changed from %s to %s", prev.status, curr.status),
170					Timestamp: now,
171				}
172			case prev != curr:
173				evt = &LifecycleEvent{
174					BeadID:    b.ID,
175					Kind:      "updated",
176					Summary:   fmt.Sprintf("bead %s updated", b.ID),
177					Timestamp: now,
178				}
179			}
