232	func normalizeWebSocketURL(url string) string {
233		switch {
234		case strings.HasPrefix(url, "http://"):
235			return "ws://" + strings.TrimPrefix(url, "http://")
236		case strings.HasPrefix(url, "https://"):
237			return "wss://" + strings.TrimPrefix(url, "https://")
238		default:
239			return url
240		}
241	}
242	
243	func cloneHeader(src http.Header) http.Header {
244		if len(src) == 0 {
245			return http.Header{}
246		}
247		dst := make(http.Header, len(src))
248		for k, values := range src {
249			dst[k] = append([]string(nil), values...)
250		}
251		return dst
252	}
253	
254	func cloneDialer(src *websocket.Dialer) *websocket.Dialer {
255		if src == nil {
256			return &websocket.Dialer{}
257		}
258		cp := *src
259		cp.Subprotocols = append([]string(nil), src.Subprotocols...)
260		return &cp

