 24		ts := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 25			conn, err := upgrader.Upgrade(w, r, nil)
 26			if err != nil {
 27				select {
 28				case errCh <- err:
 29				default:
 30				}
 31				return
 32			}
 33			defer conn.Close()
 34	
 35			fail := func(err error) {
