 37					return
 38				}
 39				select {
 40				case errCh <- err:
 41				default:
 42				}
 43			}
 44	
 45			var msg graphqlWSMessage
 46			if err := conn.ReadJSON(&msg); err != nil {
 47				fail(err)
 48				return
 49			}
 50			if msg.Type != "connection_init" {
 51				fail(&unexpectedProtocolError{got: msg.Type, want: "connection_init"})
 52				return
 53			}
 54	
 55			if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_ack"}); err != nil {
 56				fail(err)
 57				return
 58			}
 59	
 60			if err := conn.ReadJSON(&msg); err != nil {
 61				fail(err)
 62				return
 63			}
